// // This D flip-flop captures the input value on the falling edge of the clock when the enable signal is active.
module DFF (
    input clk,
    input rst_n,
    input en,
    input d,
    output reg q
);

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n)
            q <= 1'b0;
        else if (en)
            q <= d;
    end
endmodule
